INSERT INTO elemento_contenido (tipo, nombre, descripcion, sector, calificacion_promedio, destacado, activo, categoria_id, horario, url_imagen) VALUES ('LugarTuristico', 'Centro Histórico', 'El casco colonial mejor conservado de América Latina, Patrimonio de la Humanidad.', 'Centro', 4.8, 1, 1, (SELECT id FROM categoria WHERE nombre='Histórico' AND tipo='Turística' LIMIT 1), 'Lun-Dom 08:00-18:00', 'https://upload.wikimedia.org/wikipedia/commons/d/d8/Quito_Centro_Histórico.JPG'), ('LugarTuristico', 'Mitad del Mundo', 'Monumento y museo sobre la línea ecuatorial.', 'San Antonio', 4.6, 1, 1, (SELECT id FROM categoria WHERE nombre='Histórico' AND tipo='Turística' LIMIT 1), 'Lun-Dom 09:00-18:00', 'https://upload.wikimedia.org/wikipedia/commons/b/b7/Mitad_del_Mundo_01.jpg'), ('LugarTuristico', 'Teleférico de Quito', 'Ascenso al volcán Pichincha con vistas panorámicas de la ciudad.', 'Cruz Loma', 4.7, 0, 1, (SELECT id FROM categoria WHERE nombre='Aventura' AND tipo='Turística' LIMIT 1), 'Lun-Dom 09:00-17:00', 'https://www.quitoinforma.gob.ec/wp-content/uploads/2023/11/3-Teleferico.png'), ('LugarTuristico', 'Parque La Carolina', 'El pulmón verde más visitado de la ciudad moderna.', 'La Carolina', 4.4, 0, 1, (SELECT id FROM categoria WHERE nombre='Naturaleza' AND tipo='Turística' LIMIT 1), 'Lun-Dom 05:00-19:00', 'https://img.goraymi.com/2018/07/24/4327da4af2dab9157642503de7aa7eb9_xl.jpg');
