INSERT INTO elemento_contenido (tipo, nombre, descripcion, sector, calificacion_promedio, destacado, activo, categoria_id, fecha_inicio, fecha_fin, url_imagen) VALUES ('Evento', 'Fiesta de la Virgen del Quinche', 'Peregrinación y festividades religiosas tradicionales.', 'El Quinche', 4.9, 1, 1, (SELECT id FROM categoria WHERE nombre='Tradiciones' AND tipo='Cultural' LIMIT 1), '2026-11-15', '2026-11-21', 'https://www.turisec.com/wp-content/uploads/2022/11/peregrinacion.jpg'), ('Evento', 'Concierto de la Orquesta Sinfónica', 'Temporada de conciertos en el Teatro Sucre.', 'Teatro Sucre', 4.8, 0, 1, (SELECT id FROM categoria WHERE nombre='Música' AND tipo='Cultural' LIMIT 1), '2026-08-18', '2026-08-18', 'https://cdn.teatrosucre.com/wp-content/uploads/2025/04/21104323/Banda-Sinfonica-Metropolitana-de-Quito-1-1024x683.jpg'), ('Evento', 'Festival de la Luz', 'Proyecciones artísticas sobre las fachadas del Centro Histórico.', 'Centro Histórico', 4.9, 1, 1, (SELECT id FROM categoria WHERE nombre='Arte' AND tipo='Cultural' LIMIT 1), '2026-08-09', '2026-08-13', 'https://imagenes.elpais.com/resizer/v2/YO2VUTNST5KQNMFHYXQVGM2PQE.jpg?auth=6db3595b934917799e6f727be2a5e226d12a362f99479105a7c83eda2d7fdd68&width=1200');